import React from 'react';

const STRENGTH_CONFIG = [
  { label: 'Very Weak',   color: '#ff4757' },
  { label: 'Weak',        color: '#ff6b35' },
  { label: 'Fair',        color: '#ffa502' },
  { label: 'Strong',      color: '#3d7fff' },
  { label: 'Very Strong', color: '#2ed573' },
];

export default function PasswordInput({
  password, onChange, showPassword, onToggleVisibility,
  onAnalyze, loading, realtimeStrength,
}) {
  const strength = realtimeStrength;
  const config = strength ? STRENGTH_CONFIG[strength.score] : null;
  const strengthPct = strength ? ((strength.score + 1) / 5) * 100 : 0;

  const handleKey = (e) => {
    if (e.key === 'Enter') onAnalyze();
  };

  const hasLower   = /[a-z]/.test(password);
  const hasUpper   = /[A-Z]/.test(password);
  const hasDigit   = /\d/.test(password);
  const hasSpecial = /[^a-zA-Z\d]/.test(password);

  return (
    <div className="input-section">
      <label className="input-label" htmlFor="pwd-input">Enter Password to Analyze</label>
      <div className="input-wrapper">
        <div style={{ position: 'relative', flex: 1 }}>
          <input
            id="pwd-input"
            className="password-input"
            type={showPassword ? 'text' : 'password'}
            value={password}
            onChange={(e) => onChange(e.target.value)}
            onKeyDown={handleKey}
            placeholder="Type your password here..."
            autoComplete="off"
            spellCheck={false}
          />
          <button
            className="toggle-visibility"
            onClick={onToggleVisibility}
            title={showPassword ? 'Hide password' : 'Show password'}
            type="button"
          >
            {showPassword ? '🙈' : '👁️'}
          </button>
        </div>
        <button
          className="analyze-btn"
          onClick={onAnalyze}
          disabled={loading || !password}
          type="button"
        >
          {loading ? '⟳ Analyzing...' : '⚡ Analyze'}
        </button>
      </div>

      {password && strength && (
        <div className="strength-meter">
          <div className="strength-header">
            <span className="strength-label-text">Strength</span>
            <span className="strength-value" style={{ color: config?.color }}>
              {config?.label}
            </span>
          </div>
          <div className="strength-bar-track">
            <div
              className="strength-bar-fill"
              style={{ width: `${strengthPct}%`, background: config?.color }}
            />
          </div>
          <div className="strength-segments">
            {[0,1,2,3,4].map(i => (
              <div
                key={i}
                className="strength-segment"
                style={{
                  background: i <= strength.score ? STRENGTH_CONFIG[i].color : undefined,
                  opacity: i <= strength.score ? 1 : 0.2,
                }}
              />
            ))}
          </div>
          <div className="entropy-display">
            <span>⚡ Entropy:</span>
            <span className="entropy-value">{strength.entropy.toFixed(1)} bits</span>
            <span style={{ color: 'var(--text-muted)' }}>•</span>
            <span>Charset: <span className="entropy-value">{strength.charsetSize}</span></span>
            <span style={{ color: 'var(--text-muted)' }}>•</span>
            <span>Length: <span className="entropy-value">{strength.length}</span></span>
          </div>
          <div className="metadata-row">
            <span className={`meta-badge ${hasLower ? 'has' : 'no'}`}>{hasLower ? '✓' : '✗'} Lowercase</span>
            <span className={`meta-badge ${hasUpper ? 'has' : 'no'}`}>{hasUpper ? '✓' : '✗'} Uppercase</span>
            <span className={`meta-badge ${hasDigit ? 'has' : 'no'}`}>{hasDigit ? '✓' : '✗'} Numbers</span>
            <span className={`meta-badge ${hasSpecial ? 'has' : 'no'}`}>{hasSpecial ? '✓' : '✗'} Special</span>
          </div>
        </div>
      )}
    </div>
  );
}
